// Admin Performance Monitor - Track 900 siswa sync status
window.AdminPerformanceMonitor={_stats:{totalSyncs:0,successfulSyncs:0,failedSyncs:0,avgSyncTime:0,peakConcurrent:0,currentConcurrent:0,bandwidthUsed:0,startTime:Date.now()},_syncLog:[],recordSync:function(e,t,i){const n={examId:e,status:t,duration:i,timestamp:Date.now()};this._syncLog.push(n),"success"===t?(this._stats.successfulSyncs++,this._stats.avgSyncTime=(this._stats.avgSyncTime+i)/2):"failed"===t&&this._stats.failedSyncs++,this._stats.totalSyncs++,this._stats.totalSyncs%10==0&&this._logStats()},recordConcurrent:function(e){this._stats.currentConcurrent=e,e>this._stats.peakConcurrent&&(this._stats.peakConcurrent=e)},recordBandwidth:function(e){this._stats.bandwidthUsed+=e},getStats:function(){const e=Date.now()-this._stats.startTime;return{...this._stats,uptime:e,successRate:(100*this._stats.successfulSyncs/this._stats.totalSyncs).toFixed(2)+"%",recentSyncs:this._syncLog.slice(-20)}},_logStats:function(){const e=this.getStats();console.log(`[AdminMonitor] Syncs: ${e.totalSyncs} | Success: ${e.successRate} | Peak: ${e.peakConcurrent} | Bandwidth: ${(e.bandwidthUsed/1024/1024).toFixed(2)}MB`)},exportReport:function(){const e=this.getStats();return{timestamp:new Date,stats:e,logs:this._syncLog}},resetStats:function(){this._stats={totalSyncs:0,successfulSyncs:0,failedSyncs:0,avgSyncTime:0,peakConcurrent:0,currentConcurrent:0,bandwidthUsed:0,startTime:Date.now()},this._syncLog=[],console.log("[AdminMonitor] Stats reset")}};window.recordSyncEvent=function(e,t,i){window.AdminPerformanceMonitor.recordSync(e,t,i)};
